class Solution:
    def minNumberOperations(self, target):
        def solve(lo, hi, base):
            if lo > hi:
                return 0
            m = min(target[lo:hi + 1])
            cost = m - base
            i = lo
            while i <= hi:
                if target[i] == m:
                    i += 1
                    continue
                j = i
                while j <= hi and target[j] != m:
                    j += 1
                cost += solve(i, j - 1, m)
                i = j
            return cost
        return solve(0, len(target) - 1, 0)

